/* ── RTL Support ── */
/* Applied via the `gv-rtl` class on document.body when an RTL language is active. */

/* Timeline bar: move from the right edge to the left edge */
body.gv-rtl .gemini-timeline-bar {
  right: auto;
  left: 15px;
}

/* Prompt manager trigger: mirror to the left side */
body.gv-rtl .gv-pm-trigger {
  right: auto;
  left: 18px;
}

/* Preview panel: reverse the slide-in direction (from right instead of left) */
body.gv-rtl .timeline-preview-panel {
  transform: scale(0.96) translateX(-8px);
  direction: rtl;
}

body.gv-rtl .timeline-preview-panel.visible {
  transform: scale(1) translateX(0);
}

/* Preview list items: active border on the right side */
body.gv-rtl .timeline-preview-item {
  border-left: none;
  border-right: 3px solid transparent;
  padding: 6px 6px 6px 10px;
}

body.gv-rtl .timeline-preview-item.active {
  border-right-color: var(--timeline-dot-active-color);
}

/* Preview index: right-align numbers in RTL */
body.gv-rtl .timeline-preview-index {
  text-align: right;
  justify-content: flex-end;
}

/* ── Message Timestamps ── */
.gv-timestamp {
  display: flex;
  font-size: 0.9em;
  color: var(--gm-neutral-variant-50, #999);
  opacity: 0.7;
  margin: 12px 0 6px 0;
  font-weight: 400;
  user-select: none;
  line-height: 1.2;
  font-family:
    -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
}

.gv-timestamp-user {
  justify-content: flex-end;
  text-align: right;
}

.gv-timestamp-assistant {
  justify-content: flex-start;
  text-align: left;
}

/* Dark mode timestamp color */
html.dark .gv-timestamp,
[data-theme='dark'] .gv-timestamp,
[data-color-scheme='dark'] .gv-timestamp {
  color: var(--gm-neutral-variant-70, #aaa);
