  pointer-events: auto;
}

/* Invisible bridge between logo and dropdown so hover doesn't break in the gap */
.gv-logo-dropdown-wrapper::after {
  content: '';
  position: absolute;
  top: 100%;
  left: 0;
  right: 0;
  height: 12px;
  pointer-events: none;
}

