[data-color-scheme='dark'] .gv-changelog-chrome-rating-text {
  color: #bdc1c6;
}

html.dark .gv-changelog-chrome-rating-link,
[data-theme='dark'] .gv-changelog-chrome-rating-link,
[data-color-scheme='dark'] .gv-changelog-chrome-rating-link {
  background: #8ab4f8;
  color: #202124 !important;
}

html.dark .gv-changelog-chrome-rating-link:hover,
[data-theme='dark'] .gv-changelog-chrome-rating-link:hover,
[data-color-scheme='dark'] .gv-changelog-chrome-rating-link:hover {
  background: #aecbfa;
}

.gv-changelog-lightbox {
  position: fixed;
  inset: 0;
  z-index: 2147483647;
  background: rgba(0, 0, 0, 0.88);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px;
  cursor: zoom-out;
  animation: gv-lightbox-in 0.18s ease;
}

@keyframes gv-lightbox-in {
  from {
    opacity: 0;
    transform: scale(0.96);
  }

  to {
    opacity: 1;
    transform: scale(1);
  }
}

.gv-changelog-lightbox-img {
  max-width: 90vw;
  max-height: 88vh;
  border-radius: 10px;
  object-fit: contain;
  box-shadow: 0 24px 80px rgba(0, 0, 0, 0.6);
  pointer-events: none;
}

/* Changelog notification mode toggle */
.gv-changelog-notify-toggle {
  margin-bottom: 12px;
  padding: 8px 12px;
  border-radius: 8px;
  background: rgba(0, 0, 0, 0.03);
  border: 1px solid rgba(0, 0, 0, 0.06);
}

.gv-changelog-notify-label {
  display: flex;
  align-items: center;
  gap: 8px;
  cursor: pointer;
  font-size: 12.5px;
  color: #555;
  line-height: 1.4;
  user-select: none;
}

.gv-changelog-notify-checkbox {
  width: 15px;
  height: 15px;
  margin: 0;
  cursor: pointer;
  accent-color: #1a73e8;
  flex-shrink: 0;
}

html.dark .gv-changelog-notify-toggle,
[data-theme='dark'] .gv-changelog-notify-toggle,
[data-color-scheme='dark'] .gv-changelog-notify-toggle {
  background: rgba(255, 255, 255, 0.04);
  border-color: rgba(255, 255, 255, 0.08);
}

html.dark .gv-changelog-notify-label,
[data-theme='dark'] .gv-changelog-notify-label,
[data-color-scheme='dark'] .gv-changelog-notify-label {
  color: #9aa0a6;
}

/* ── RTL Support ── */
/* Applied via the `gv-rtl` class on document.body when an RTL language is active. */

/* Timeline bar: move from the right edge to the left edge */
body.gv-rtl .gemini-timeline-bar {
  right: auto;
  left: 15px;
}

/* Prompt manager trigger: mirror to the left side */
body.gv-rtl .gv-pm-trigger {
  right: auto;
  left: 18px;
}

/* Preview panel: reverse the slide-in direction (from right instead of left) */
body.gv-rtl .timeline-preview-panel {
  transform: scale(0.96) translateX(-8px);
  direction: rtl;
}

body.gv-rtl .timeline-preview-panel.visible {
  transform: scale(1) translateX(0);
}

/* Preview list items: active border on the right side */
body.gv-rtl .timeline-preview-item {
  border-left: none;
  border-right: 3px solid transparent;
  padding: 6px 6px 6px 10px;
}

body.gv-rtl .timeline-preview-item.active {
  border-right-color: var(--timeline-dot-active-color);
}

/* Preview index: right-align numbers in RTL */
body.gv-rtl .timeline-preview-index {
  text-align: right;
  justify-content: flex-end;
}

/* ── Message Timestamps ── */
.gv-timestamp {
  display: flex;
  font-size: 0.9em;
  color: var(--gm-neutral-variant-50, #999);
  opacity: 0.7;
  margin: 12px 0 6px 0;
  font-weight: 400;
  user-select: none;
  line-height: 1.2;
  font-family:
    -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
}

.gv-timestamp-user {
  justify-content: flex-end;
  text-align: right;
}

.gv-timestamp-assistant {
  justify-content: flex-start;
  text-align: left;
}

/* Dark mode timestamp color */
html.dark .gv-timestamp,
[data-theme='dark'] .gv-timestamp,
[data-color-scheme='dark'] .gv-timestamp {
  color: var(--gm-neutral-variant-70, #aaa);
}

/* RTL support for timestamps */
body.gv-rtl .gv-timestamp {
  text-align: right;
}

