@keyframes gv-export-progress-spin {
  from {
    transform: rotate(0);
  }

  to {
    transform: rotate(360deg);
  }
}

@media (max-width: 640px) {
  .gv-export-select-bar {
    left: 10px;
    right: 10px;
    top: 10px;
    transform: none;
    justify-content: space-between;
    gap: 8px;
  }

  .gv-export-select-all-toggle {
    min-width: 62px;
    padding: 0 10px;
  }

  .gv-export-select-count {
    min-width: 82px;
    font-size: 12px;
