/* Folder Content (conversations and subfolders) */
.gv-folder-content {
  display: flex;
  flex-direction: column;
  gap: 2px;
  margin-top: 2px;
  margin-left: 12px;
  padding-left: 8px;
  border-left: 1px solid var(--folder-border);
}

/* Conversation Item in Folder */
.gv-folder-conversation {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 8px 6px;
  border-radius: 8px;
  cursor: pointer;
  transition:
    background-color 0.15s ease,
    opacity 0.2s;
  position: relative;
}

